package br.com.pueria.pueria.relatorios;
import org.springframework.http.*; import org.springframework.security.core.Authentication; import org.springframework.web.bind.annotation.*; import java.util.UUID;
@RestController @RequestMapping("/api/criancas/{criancaId}/relatorio-consulta") public class ResumoConsultaController { private final ResumoConsultaPdfService service; public ResumoConsultaController(ResumoConsultaPdfService service){this.service=service;} @GetMapping(produces=MediaType.APPLICATION_PDF_VALUE) public ResponseEntity<byte[]> gerar(@PathVariable UUID criancaId,@RequestParam(defaultValue="false") boolean detalhado,Authentication auth){String arquivo=detalhado?"resumo-consulta-detalhado.pdf":"resumo-consulta.pdf";return ResponseEntity.ok().header(HttpHeaders.CONTENT_DISPOSITION,"inline; filename="+arquivo).body(service.gerar(criancaId,auth.getName(),detalhado));} }
